from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/search')
def search():
    query = request.args.get('q')

    results = {
        'query': query,
        'results': []
    }

    for i in range(10):
        result = {
            'title': 'Result ' + str(i),
            'url': 'https://www.example.com/' + str(i)
        }
        results['results'].append(result)

    html = '''
    <h1>Search Results for: {}</h1>
    <ul>
    {}
    </ul>
    '''.format(query, ''.join(['<li><a href="{}">{}</a></li>'.format(result['url'], result['title']) for result in results['results']]))

    return html

import jinja2

def render_menu(menu):
    template_str = "Dinner menu: {{ menu['main_course'] }} with sides of {{ menu['sides'][0] }} and {{ menu['sides'][1] }}. Dessert is {{ menu['dessert'] }}."

    env = jinja2.Environment(autoescape=True)
    template = env.from_string(template_str)

    return template.render(menu=menu)

